class Solution {
public:
    bool isSubstringPresent(string s) {
        for (int i = 0; i < s.length() - 1; i++) {
            for (int j = i + 1; j < s.length(); j++) {
                string substring = s.substr(i, 2);
                if (s.rfind(substring) != string::npos) {
                    return true;
                }
            }
        }
        return false;
    }
};
